local TD = TD.td1madao["ydj_dst_td1madao"] TD.createFn("hasC", function(inst, name, fun, ...)     if not inst or not TD.isStr(name) then         return     end     local comp = inst.components[name]     if TD.isFn(fun) and comp ~= nil then         fun(comp, ...)     end     return comp ~= nil end) TD.createFn("initC", function(inst, name, fun, ...)     if not inst or not TD.isStr(name) then         return     end     local n, v = select("#", ...), { ... }     TD.addC(inst, name, function()         if TD.isFn(fun) then             fun(inst.components[name], unpack(v, 1, n))         end     end)     return inst.components[name] end) TD.createFn("rmC", function(inst, name)     if not inst or not TD.isStr(name) or not inst.components then         return     end     if inst.components[name] then         inst:RemoveComponent(name)     end end) TD.createFn("addC", function(inst, name, fun, ...)     if not inst or not TD.isStr(name) or not inst.components then         return     end               if inst.replica and inst.replica[name] and not TD.server() then         return     end     if not inst.components[name] then         inst:AddComponent(name)     end     local component = inst.components[name]     if TD.isFn(fun) then         fun(component, ...)     end     return component end) TD.createFn("getC", function(inst, name, fun, ...)     return TD.addC(inst, name, fun, ...) end) TD.createFn("callC", function(inst, name, fun, ...)     return TD.addC(inst, name, fun, ...) end) TD.createFn("cem", function(inst, fun, ...)     return TD.getC(inst, TD.holder("%s_global_event_manager"), fun, ...) end) TD.createFn("cpr", function(inst, fun, ...)     return TD.getC(inst, TD.holder("%s_global_perioder"), fun, ...) end) TD.createFn("csv", function(inst, fun, ...)               if not inst then         return     end     if TD.isStr(inst.td1madao_csv_permanent_msg) then         return TD.getC(inst, inst.td1madao_csv_permanent_msg, fun, ...)     end     if inst.td1madao_prefab then         inst.td1madao_csv_permanent_msg = string.format("%s_global_saver", inst.td1madao_prefab)         return TD.getC(inst, inst.td1madao_csv_permanent_msg, fun, ...)     end     if inst.prefab and inst.components[string.format("%s_global_saver", inst.prefab)] then         inst.td1madao_csv_permanent_msg = string.format("%s_global_saver", inst.prefab)         return TD.getC(inst, inst.td1madao_csv_permanent_msg, fun, ...)     end     inst.td1madao_csv_permanent_msg = "global_td1madao_global_saver"     return TD.getC(inst, inst.td1madao_csv_permanent_msg, fun, ...) end) TD.createFn("csa", function(inst, fun, ...)     return TD.getC(inst, TD.holder("%s_global_skill_attributer"), fun, ...) end) TD.createFn("csm", function(inst, fun, ...)     return TD.getC(inst, TD.holder("%s_global_skill_manager"), fun, ...) end) TD.createFn("ctm", function(inst, fun, ...)     return TD.getC(inst, TD.holder("%s_global_task_manager"), fun, ...) end) TD.createFn("cvm", function(inst, fun, ...)     return TD.getC(inst, TD.holder("%s_global_version_manager"), fun, ...) end) TD.createFn("mgn", function(inst, fun, ...)          if not inst then         return     end     if TD.isStr(inst.td1madao_msg_permanent_msg) then         return TD.getC(inst, inst.td1madao_msg_permanent_msg, fun, ...)     end     if inst.td1madao_prefab then         local msg_comp = string.format("%s_global_notify_v3", inst.td1madao_prefab)         inst.td1madao_msg_permanent_msg = msg_comp         return TD.getC(inst, msg_comp, fun, ...)     end     if inst.prefab and inst.components[string.format("%s_global_notify", inst.prefab)] then         local msg_comp = string.format("%s_global_notify", inst.prefab)         inst.td1madao_msg_permanent_msg = msg_comp         return TD.getC(inst, msg_comp, fun, ...)     end          for i = 1, 10 do         if inst.prefab and inst.components[string.format("%s_global_notify_v" .. tostring(i), inst.prefab)] then             local msg_comp = string.format("%s_global_notify_v" .. tostring(i), inst.prefab)             inst.td1madao_msg_permanent_msg = msg_comp             return TD.getC(inst, msg_comp, fun, ...)         end     end     local msg_comp = TD.holder("%s_global_notify_v3")     inst.td1madao_msg_permanent_msg = msg_comp     return TD.getC(inst, msg_comp, fun, ...) end) TD.createFn("cbm", function(inst, fun, ...)     return TD.getC(inst, TD.holder("%s_global_buff_manager"), fun, ...) end) TD.createFn("cse", function(inst, fun, ...)     return TD.getC(inst, TD.holder("%s_global_skill_effect"), fun, ...) end) TD.createFn("clt", function(inst, fun, ...)     return TD.getC(inst, TD.holder("%s_global_lighter"), fun, ...) end) TD.createFn("cRegister", function(inst, arr)     if inst and TD.isTab(arr) then         TD.fori(arr, function(k, v)             if TD.isStr(v) and TD[v] then                 TD[v](inst)             end         end)     end end) TD.createFn("cRegister2", function(inst, arr)     if inst and TD.isTab(arr) then         TD.fori(arr, function(k, v)             if TD.isFn(v) then                 v(inst)             end         end)     end end) TD.createFn("talk", function(inst, word)     if inst and inst.components.talker and TD.isStr(word) then         inst.components.talker:Say(word, nil, true)     end end) TD.createFn("hungerDelta", function(inst, num)     if inst and TD.hasC(inst, "hunger") and TD.isNum(num) then         local hungerC = TD.getC(inst, "hunger")         if TD.isNum(hungerC.current) then             local old = hungerC.current             local current = old + num             if current < 0 then                 current = 0             end             hungerC.current = current         end     end end) TD.createFn("getOwner", function(inst, fun)     local result     TD.hasC(inst, "inventoryitem", function(comp)         local owner = comp.owner         if owner ~= nil and TD.isFn(fun) then             fun(owner)         end         result = owner     end)     return result end) TD.createFn("dropOrHand", function(inst)     local owner = TD.getOwner(inst)     if not owner then         return true     end     local all = {         _G.EQUIPSLOTS.BACK,         _G.EQUIPSLOTS.NECK,         _G.EQUIPSLOTS.PACK,         _G.EQUIPSLOTS.HANDS,         _G.EQUIPSLOTS.HEAD,     }     local equiped = false     TD.hasC(owner, "inventory", function(comp)         TD.fori(all, function(k, v)             if k ~= nil and v ~= nil then                 local item = comp:GetEquippedItem(v)                 if inst == item then                     equiped = true                     return true                 end             end         end)     end)     return equiped end) TD.createFn("refusePlayer", function(inst, item)     if inst and inst.prefab ~= TD.CHAR then         inst:DoTaskInTime(0, function()             TD.hasC(inst, "inventory", function(comp)                 TD.hasC(item, "inventoryitem", function()                     comp:GiveItem(item)                 end)             end)             TD.hasC(inst, "talker", function(comp)                 comp:Say(STRINGS[TD.holder("%s_TD1MADAO")].UNFIT_WEAPON or "NO!")             end)         end)         return     end end) TD.createFn("returnItem", function(inst, item)     inst:DoTaskInTime(0, function()         TD.hasC(inst, "inventory", function(comp)             TD.hasC(item, "inventoryitem", function()                 comp:GiveItem(item)             end)         end)     end) end) TD.createFn("unequipItem", function(inst, item)     TD.hasC(item, "equippable", function(comp)         comp:Unequip(inst)     end) end) TD.createFn("refuseInventory", function(inst, item, fn)     if inst and inst:HasTag("player") and inst.prefab ~= TD.CHAR then         inst:DoTaskInTime(0, function()             TD.hasC(inst, "inventory", function(comp)                 TD.hasC(item, "inventoryitem", function()                     comp:DropItem(item)                 end)             end)             TD.hasC(inst, "talker", function(comp)                 comp:Say(STRINGS[TD.holder("%s_TD1MADAO")].UNFIT_WEAPON or "NO!")             end)         end)         return     elseif TD.isFn(fn) then         fn()     end end) 